#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> insertBeforeHead(vector<int>& nums, int newVal) {
        vector<int> res;
        res.reserve(nums.size() + 1);
        res.push_back(newVal);
        res.insert(res.end(), nums.begin(), nums.end());
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    int newVal;
    bool hasNewVal = true;
    if (!(cin >> newVal)) {
        hasNewVal = false;
    }
    Solution sol;
    vector<int> result;
    if (hasNewVal) {
        result = sol.insertBeforeHead(nums, newVal);
    } else {
        result = nums; // no insertion
    }
    cout << result.size() << "\n";
    for (int v : result) {
        cout << v << "\n";
    }
    return 0;
}
